patch:
diff --git a/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp b/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp
index 0633388cd411..2df83384fd4c 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp
@@ -2921,6 +2921,30 @@ Instruction *InstCombinerImpl::visitSelectInst(SelectInst &SI) {
   if (Instruction *R = foldSelectOfBools(SI))
     return R;

+  // select (select C1, C2, false), V1, (select C1, V2, V3) -> select C1, select C2, V1, V2, V3
+  // This factors out the common condition C1 from the nested selects.
+  if (auto *CondSI = dyn_cast<SelectInst>(CondVal)) {
+    Value *C1 = CondSI->getCondition();
+    Value *C2 = CondSI->getTrueValue();
+    Value *CondFalse = CondSI->getFalseValue();
+    // Match condition: select C1, C2, false
+    if (match(CondFalse, m_Zero()) && CondSI->hasOneUse()) {
+      // Match false value: select C1, V2, V3
+      if (auto *FalseSI = dyn_cast<SelectInst>(FalseVal)) {
+        if (FalseSI->getCondition() == C1) {
+          Value *V2 = FalseSI->getTrueValue();
+          Value *V3 = FalseSI->getFalseValue();
+          Value *InnerSel = Builder.CreateSelect(C2, TrueVal, V2);
+          InnerSel->takeName(FalseSI);
+          replaceOperand(SI, 0, C1);
+          replaceOperand(SI, 1, InnerSel);
+          replaceOperand(SI, 2, V3);
+          return &SI;
+        }
+      }
+    }
+  }
+
   // Selecting between two integer or vector splat integer constants?
   //
   // Note that we don't handle a scalar select of vectors:

